  describe('notification ordering', () => {
    it('should deliver notifications to the same recipient in order even when sent concurrently', async () => {
      const deliveryOrder: string[] = [];

      // Adapter where the first call is slower than the second,
      // which would cause out-of-order delivery without queuing.
      const delayAdapter: NotificationAdapter = {
        channel: 'email' as const,
        async send(payload: NotificationPayload): Promise<NotificationResult> {
          const delay = payload.type === 'order-confirmation' ? 50 : 10;
          await new Promise((resolve) => setTimeout(resolve, delay));
          deliveryOrder.push(payload.type);
          return {
            notificationId: payload.id,
            channel: 'email',
            success: true,
            deliveredAt: new Date(),
          };
        },
      };

      const orderingBus = new EventBus();
      const orderingService = new NotificationService(orderingBus);
      orderingService.registerAdapter(delayAdapter);

      // Fire both sends concurrently for the same recipient.
      // Without queuing, the faster one (order-status-update, 10ms)
      // would arrive before the slower one (order-confirmation, 50ms).
      const p1 = orderingService.send({
        type: 'order-confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Order Placed',
        body: 'Your order has been placed.',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      });

      const p2 = orderingService.send({
        type: 'order-status-update',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Payment Confirmed',
        body: 'Your payment has been confirmed.',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      });

      await Promise.all([p1, p2]);

      // Despite the first send being slower, ordering must be preserved
      expect(deliveryOrder).toEqual(['order-confirmation', 'order-status-update']);
    });

    it('should not block notifications to different recipients', async () => {
      const deliveryOrder: string[] = [];

      const delayAdapter: NotificationAdapter = {
        channel: 'email' as const,
        async send(payload: NotificationPayload): Promise<NotificationResult> {
          const delay = payload.recipient === 'alice@example.com' ? 50 : 10;
          await new Promise((resolve) => setTimeout(resolve, delay));
          deliveryOrder.push(payload.recipient);
          return {
            notificationId: payload.id,
            channel: 'email',
            success: true,
            deliveredAt: new Date(),
          };
        },
      };

      const orderingBus = new EventBus();
      const orderingService = new NotificationService(orderingBus);
      orderingService.registerAdapter(delayAdapter);

      // Different recipients should not block each other
      const p1 = orderingService.send({
        type: 'order-confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Order Placed',
        body: 'Your order has been placed.',
        priority: 'normal',
      });

      const p2 = orderingService.send({
        type: 'order-confirmation',
        channel: 'email',
        recipient: 'bob@example.com',
        subject: 'Order Placed',
        body: 'Your order has been placed.',
        priority: 'normal',
      });

      await Promise.all([p1, p2]);

      // Bob's notification (10ms) should arrive before Alice's (50ms)
      // because they're different recipients and shouldn't block each other
      expect(deliveryOrder).toEqual(['bob@example.com', 'alice@example.com']);
    });
  });
});

